actionConfiguration.body:
{{(() => {
	// Validate required fields
	if (!NewPickupAddressInput.text || !NewDropoffAddressInput.text) {

		throw new Error("Pickup and delivery addresses are required");
	}

	if (!NewPickupLatHidden.text || !NewPickupLngHidden.text || 
			!NewDropoffLatHidden.text || !NewDropoffLngHidden.text) {

		throw new Error("Address geocoding is required - please wait for location validation");
	}

    // Get service quote UUID from the creation query result
 const serviceQuoteUuid = GetCreatedServiceQuote.data[0].service_quote_uuid;

	if (!serviceQuoteUuid) {
        throw new Error("Failed to create service quote. Please try again.");
    }


	const customer = appsmith.store.customer_uuid;

	return {
		"order": {
			"internal_id": OrderSourceIdInput.text || "",
			"customer_uuid": customer,
			"service_quote_uuid": serviceQuoteUuid,
			"order_config_uuid": "a0e5f3b9-68e4-4490-95c6-e39ccddbcf32",
			"customer_type": "fleet-ops:contact",
			"type": "e-commerce-with-cod",
			"scheduled_at": ScheduledDeliveryPicker.selectedDate,
			"notes": DeliveryNotesInput.text,
			"payload": {
				"pickup": {
					"name": NewPickupAddressInput.text?.split(',')[0] || "Pickup Location",
					"address": NewPickupAddressInput.text || "",
					"location": {
						"type": "Point",
						"coordinates": [
							parseFloat(NewPickupLngHidden.text), 
							parseFloat(NewPickupLatHidden.text)
						]
					}
				},
				"dropoff": {
					"name": NewDropoffAddressInput.text?.split(',')[0] || "Delivery Location", 
					"address": NewDropoffAddressInput.text || "",
					"location": {
						"type": "Point",
						"coordinates": [
							parseFloat(NewDropoffLngHidden.text), 
							parseFloat(NewDropoffLatHidden.text)
						]
					}
				},
				"entities": (appsmith.store.newOrderItems || []).map(item => ({
					"name": item.name,
					"price": item.price ? parseFloat(item.price) : 0,
					"sku": item.sku || ""
				}))
			},
			"custom_field_values": [
				{
					"custom_field_uuid": "080da746-4a5a-4f4d-9afa-78f215fc4971",
					"value": StoreTypeSelect.selectedOptionValue,
					"value_type": "text"
				},
				{
					"custom_field_uuid": "cc8ba2d8-3e0e-4ba6-8a85-61ed89254f9d",
					"value": OrderSourceIdInput.text || "",
					"value_type": "text"
				},
				{
					"custom_field_uuid": "79707269-ef79-4e2c-b63b-eaf76f4a3f85",
					"value": NewPaymentMethodSelect.selectedOptionValue,
					"value_type": "text"
				},
				{
					"custom_field_uuid": "d0b5b899-6cfc-4eef-a898-ec99a23ef039",
					"value": NewAmountInput.text,
					"value_type": "text"
				},

      {"custom_field_uuid": "8e9a772d-2694-4750-8c8c-f8e9e6996ac2",
      "value": (() => {
          const selectedService = GetAvailableServiceRates.data?.find(
              r => r.service_rate_uuid === OrderShippingSelect.selectedOptionValue
          );
          return selectedService?.service_name?.includes('-express') ? 'Express' : 'Standard';
      })(),
      "value_type": "select"
			}
			]
		}
	};
})()}}
